class RTDetrV2Encoder(nn.Module):
    def __init__(self, config: RTDetrV2Config):
        super().__init__()

        self.layers = nn.ModuleList([RTDetrV2EncoderLayer(config) for _ in range(config.encoder_layers)])

    def forward(self, src, src_mask=None, pos_embed=None, output_attentions: bool = False) -> torch.Tensor:
        hidden_states = src
        for layer in self.layers:
            hidden_states = layer(
                hidden_states,
                attention_mask=src_mask,
                position_embeddings=pos_embed,
                output_attentions=output_attentions,
            )
        return hidden_states

class RTDetrV2Encoder(nn.Module) {
  __init__(config:RTDetrV2Config) = ModuleList([RTDetrV2EncoderLayer(config) for _ in config.encoder_layers])

  forward(src, src_mask=None, pos_embed=None, output_attentions=False)->Tensor = 
    src |> λh: [layer(h, mask=src_mask, pos=pos_embed, output_attentions=o_a) for layer in layers] |> h
